#include <bits/stdc++.h>
using namespace std;
int n,dp[1505][2],vis[1505];
vector<int> G[1505];
void dfs(int x,int fa)
{
    dp[x][1]=1;
    for(int i=0;i<G[x].size();i++)
    {
        int t=G[x][i];
        if(t==fa) continue;
        dfs(t,x);
        dp[x][0]+=dp[t][1];
        dp[x][1]+=min(dp[t][0],dp[t][1]);
    }
}
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        int x,k;
        cin>>x>>k;
        for(int j=1;j<=k;j++)
        {
            int t;
            cin>>t;
            vis[t]=1;
            G[x].push_back(t);
        }
    }
    int root;
    for(int i=0;i<n;i++)
    {
        if(!vis[i])
        {
            root=i;
            break;
        }
    }
    dfs(root,-1);
    cout<<min(dp[root][0],dp[root][1]);
    return 0;
}
